module sr_latch (
    input wire s,
    input wire r,
    input wire rst_n,
    output reg obf_q
);

    always @(*) begin
        if (!rst_n) begin
            obf_q <= 1'b0;
        end else if (s && !r) begin
            obf_q <= 1'b1;
        end else if (!s && r) begin
            obf_q <= 1'b0;
        end
    end

endmodule
